defmodule DevOpsWeb.CommandController do
  use DevOpsWeb, :controller

  def run(conn, %{"command" => command}) do
    {output, status} = System.cmd("sh", ["-c", command], stderr_to_stdout: true)

    if status == 0 do
      conn
      |> put_status(:ok)
      |> json(%{message: "Command executed successfully", output: output})
